const signIn=()=>firebase.auth().signInAnonymously().catch(e=>alert(e.code))
signIn()
const onAuth=cb=>firebase.auth().onAuthStateChanged(u=>{ if(u) cb(u.uid) })
const cuid=()=> firebase.auth().currentUser.uid
const qndb = firebase.firestore().collection('questions')
function handleQuestion(form, cb){
    form.uid = cuid(); form.totScore = 0
    if(form.action==='发布'){
        qndb.add(form).then(d=>alert('成功')).catch(e=>alert(e.code)).then(()=>cb())
    }
}
const ansdb = firebase.firestore().collection('answers')
function handleAnswer(form, cb){
    form.uid = cuid(); form.totScore = 0
    if(form.action==='发布'){
        ansdb.add(form).then(d=>alert('成功')).catch(e=>alert(e.code)).then(()=>cb())
    }
}
function handleReply(db,c,id, cb){
    var score = c==='👎'? -1 : 1
    db.doc(id).collection('reply').doc(cuid()).set({score}).then(()=>{
        db.doc(id).collection('reply').get().then(s=>{
            var totScore = 0
            s.forEach(d=> totScore+=d.data().score )
            db.doc(id).update({totScore})
            cb(totScore)
        })
    })
}

const levels = ['小学','初中','高中','大学','硕博']
const subjects = ['数学','物理','化学','生物','计算机','电子','材料']
const fields = [{t:'问题',n:1},{t:'详情',n:6}]
const ansFields = [{t:'详情',n:6}]
const actions = ['发布'] // '🔄','⏪','⏩','💾',
const reply = ['👎','🧡']
const viewActs = ['回答']
const pages = ['提问']

const Dum=()=><View style={{flex:1}}></View>
const Row=({children,jc='center',ph=10})=>(
    <View style={{flexDirection:'row',flexWrap:'wrap',alignItems:'center',justifyContent:jc,paddingHorizontal:ph}}>{children}</View>
)
const Txt=({children, c='white', s, b=1})=><Text style={{color:c,fontSize:s,fontWeight:b&&'bold'}}>{children}</Text>

const Ipt=({children, on, p, n, c='blue', s=20, b=1, bw=3, bc='aqua', m=3, ph=20, pv=3, r=20})=>(
    <TextInput onChangeText={on} placeholder={p} value={children} numberOfLines={n} multiline={n>1} style={{
        color:c,fontSize:s,fontWeight:b&&'bold',outline:'none',
        borderWidth:bw,borderColor:bc,margin:m,paddingHorizontal:ph,paddingVertical:pv,borderRadius:r,
    }}></TextInput>
)
const Ipts=({children, on, f0={}})=>{
    const [form, setForm] = useState(f0)
    const set=(k,v)=>{var o={...form};o[k]=v;setForm(o);return o}
    return children.map((c,idx)=><Ipt key={idx} on={t=>on(set(c.t,t))} p={c.t} n={c.n}>{form[c.t]}</Ipt>)
}

const Btn=({children, on, bg='grey', m=3, ph=10, pv=3, r=20})=>(
    <TouchableOpacity onPress={on} style={{backgroundColor:bg,margin:m,paddingHorizontal:ph,paddingVertical:pv,borderRadius:r}}>
        <Txt>{children}</Txt>
    </TouchableOpacity>
)
const Btns=({children, on, a0, cs=['grey','blue']})=>{
    const [act, setAct] = useState(a0)
    return children.map((c,idx)=><Btn key={idx} on={()=>{on(c); setAct(c)}} bg={act===c?cs[1]:cs[0]}>{c}</Btn>)
}

const QnCard=({id,db,data,idx, on=()=>{},n=1, bg='beige', m=6, ph=20, pv=3, r=10})=>{
    const nav = useNavigation()
    const [score,setScore] = useState(data.totScore)
    return <View style={{borderTopColor:'aqua',borderTopWidth:2}}>
        <TouchableOpacity onPress={()=>{on(); if(n) nav.navigate('查看',{id, data})}} style={{backgroundColor:bg,margin:m,paddingHorizontal:ph,paddingVertical:pv,borderRadius:r}}>
            <Txt c='black' s={14}>{data.fields.问题}</Txt>
            <Txt c='grey'>{data.fields.详情}</Txt>
        </TouchableOpacity>
        <Row ph={ph}>
            <Txt c='blue'>🧡-👎={score}</Txt><Dum></Dum>
            <Btns on={c=>{handleReply(db,c,id, s=>setScore(s))}} cs={['white','aqua']}>{reply}</Btns>
        </Row>
    </View>
}
const List=({children,db, C, on=()=>{},n, a0, cs=['white','aqua']})=>{
    const [act, setAct] = useState(a0)
    return <FlatList data={Object.entries(children)} keyExtractor={item=>item[0]} renderItem={({item,index})=>(
        <C id={item[0]} db={db} data={item[1]} idx={index} n={n} on={()=>{on(item[0]); setAct(item[0])}} bg={act===item[0]?cs[1]:cs[0]}></C>
    )}></FlatList>
}

const Stack = createStackNavigator()
const Tab = createBottomTabNavigator()
export default function App(){
    return(
        <View style={{height:'100vh'}}>
            <NavigationContainer>
                <Stack.Navigator>
                    <Stack.Screen name='Tabs' component={Tabs}></Stack.Screen>
                    <Stack.Screen name='提问' component={提问}></Stack.Screen>
                    <Stack.Screen name='回答' component={回答}></Stack.Screen>
                </Stack.Navigator>
            </NavigationContainer>
        </View>
    )
}
const Tabs=()=>(
    <Tab.Navigator>
        <Tab.Screen name='浏览' component={浏览}></Tab.Screen>
        <Tab.Screen name='查看' component={查看}></Tab.Screen>
    </Tab.Navigator>
)

function 提问(){
    const nav = useNavigation()
    const [form, setForm] = useState({
        level:'大学',subject:'物理',fields:{问题:'',详情:''},action:actions[0],
    })
    const set=(k,v)=>{var o={...form};o[k]=v;setForm(o);return o}
    return(
        <View style={{padding:5}}>
            <Row><Btns on={c=>{set('level',c)}} a0={form.level}>{levels}</Btns></Row>
            <Row><Btns on={c=>{set('subject',c)}} a0={form.subject}>{subjects}</Btns></Row>
            <Ipts on={f=>{set('fields',f)}} f0={form.fields}>{fields}</Ipts>
            <Row><Btns on={c=>{handleQuestion(set('action',c),()=>nav.goBack() )}} a0={form.action} cs={['black','red']}>{actions}</Btns></Row>
        </View>
    )
}

function 回答(){
    const nav = useNavigation()
    const p = useRoute().params
    const [form, setForm] = useState({
        fields:{详情:''},action:actions[0],qnId:p.id,
    })
    const set=(k,v)=>{var o={...form};o[k]=v;setForm(o);return o}
    return(
        <View style={{padding:5}}>
            {p? <QnCard db={qndb} id={p.id} data={p.data} n={0}></QnCard> :undefined}
            <Ipts on={f=>{set('fields',f)}} f0={form.fields}>{ansFields}</Ipts>
            <Row><Btns on={c=>{handleAnswer(set('action',c),()=>nav.goBack() )}} a0={form.action} cs={['black','red']}>{actions}</Btns></Row>
        </View>
    )
}

function 浏览(){
    const nav = useNavigation()
    const [form, setForm] = useState({level:'大学',subject:'物理'})
    const [data, setData] = useState({})
    const [uid, setUid] = useState(); useEffect(()=>{ onAuth(u=>setUid(u)) },[])
    useEffect(()=>{
        qndb.where('level','==',form.level).where('subject','==',form.subject).onSnapshot(s=>{
            var data_ = {}; s.forEach(d=>data_[d.id]=d.data()); setData(data_); console.log(data_)
        })
    },[form])
    const set=(k,v)=>{var o={...form};o[k]=v;setForm(o);return o}
    return(
        <View style={{flex:1}}>
            <Row><Btn bg='black'>萤雪 问答平台, v1, 共204行代码</Btn></Row>
            <Row><Btns on={c=>{set('level',c)}} a0={form.level}>{levels}</Btns></Row>
            <Row><Btns on={c=>{set('subject',c)}} a0={form.subject}>{subjects}</Btns></Row>
            {uid?<List db={qndb} C={QnCard}>{data}</List>:undefined}
            {uid?<Row><Btns on={c=>{nav.navigate(c)}} a0={pages[0]}>{pages}</Btns></Row>:undefined}
        </View>
    )
}

function 查看(){
    const nav = useNavigation()
    const p = useRoute().params
    const [data, setData] = useState({})
    const [uid, setUid] = useState(); useEffect(()=>{ onAuth(u=>setUid(u)) },[])
    useEffect(()=>{
        if(!p) return 
        ansdb.where('qnId','==',p.id).onSnapshot(s=>{
            var data_ = {}; s.forEach(d=>data_[d.id]=d.data()); setData(data_); console.log(data_)
        })
    },[p])    
    return(
        <View style={{flex:1}}>
            {p? <QnCard db={qndb} id={p.id} data={p.data} n={0}></QnCard> :undefined}
            {p&&uid?<List db={ansdb} C={QnCard} n={0}>{data}</List>:undefined}
            {p&&uid?<Row><Btns on={c=>{nav.navigate(c,p)}} a0={viewActs[0]}>{viewActs}</Btns></Row>:undefined}
        </View>
    )
}